query:
SELECT article_potential, COUNT(*) as cnt 
FROM selector_candidates 
WHERE status = 'pending'
GROUP BY article_potential;

SELECT COUNT(*) as total_pending FROM selector_candidates WHERE status = 'pending';
SELECT COUNT(*) as total_articles FROM articles;
SELECT COUNT(*) as published_today FROM articles 
WHERE DATE(createdAt) = CURDATE() AND status IN ('published','pending_approval');

